import type { Metadata } from "next";
import Link from "next/link";
import { JsonLd } from "@/components/json-ld";
import { SERVICES, SERVICE_ORDER } from "@/lib/restoration-data";
import { EMERGENCY_PHONE_DISPLAY, SITE_NAME, absoluteUrl } from "@/lib/seo";

export const metadata: Metadata = {
  title: "Emergency Restoration Service Hubs",
  description:
    "Browse service hubs for emergency water damage restoration, fire damage restoration, mold remediation, and hazmat cleanup across Canadian cities.",
  alternates: {
    canonical: "/services",
  },
  openGraph: {
    title: `${SITE_NAME} Service Hubs`,
    description:
      "Structured service pages with definitions, process steps, local internal links, and direct emergency call actions.",
    type: "website",
    url: absoluteUrl("/services"),
    siteName: SITE_NAME,
  },
  twitter: {
    card: "summary_large_image",
    title: `${SITE_NAME} Service Hubs`,
    description: "Open a service hub, pick a city page, and call for emergency dispatch.",
  },
  keywords: [
    "emergency restoration services canada",
    ...SERVICE_ORDER.map((serviceSlug) => SERVICES[serviceSlug].name.toLowerCase()),
  ],
};

export default function ServicesPage() {
  const listSchema = {
    "@context": "https://schema.org",
    "@type": "ItemList",
    name: "Restoration Service Hubs",
    itemListElement: SERVICE_ORDER.map((serviceSlug, index) => {
      const service = SERVICES[serviceSlug];
      return {
        "@type": "ListItem",
        position: index + 1,
        name: service.name,
        url: absoluteUrl(`/services/${service.slug}`),
      };
    }),
  };

  return (
    <main className="iris-shell">
      <JsonLd data={listSchema} />

      <section className="iris-hero iris-section py-14">
        <div className="iris-container">
          <Link href="/" className="iris-btn iris-btn-secondary">
            Back to Home
          </Link>
          <h1 className="iris-hero-title mt-5">
            {SITE_NAME}
            <span>Canadian Service Hubs</span>
          </h1>
          <p className="iris-hero-lead">
            Pick a service, open the right location page, and call {EMERGENCY_PHONE_DISPLAY} for immediate help.
          </p>
        </div>
      </section>

      <section className="iris-section">
        <div className="iris-container space-y-8">
          <div className="iris-block">
            <h2 className="iris-title text-2xl">Quick Answer</h2>
            <p className="iris-subtitle">
              <strong>Best page structure for emergency intent:</strong> service hub first, then city page with clear
              call action and process detail.
            </p>
          </div>
          <div className="iris-divider" />

          <div className="grid gap-6 md:grid-cols-2">
            {SERVICE_ORDER.map((serviceSlug) => {
              const service = SERVICES[serviceSlug];
              return (
                <Link key={service.slug} href={`/services/${service.slug}`} className="iris-card iris-card-pad">
                  <p className="text-xs font-bold uppercase tracking-[0.2em] text-[#1e4a63]">{service.navLabel}</p>
                  <h2 className="mt-2 text-2xl font-bold text-[#0d2d44]">{service.name}</h2>
                  <p className="mt-3 text-[#5c6875]">{service.shortDescription}</p>
                  <span className="iris-btn iris-btn-dark mt-5">Open {service.name} Hub</span>
                </Link>
              );
            })}
          </div>

          <div className="grid gap-6 lg:grid-cols-3">
            <div className="iris-band-soft rounded-2xl px-6 py-8 lg:col-span-2">
              <h2 className="iris-title text-2xl">How These Service Hubs Are Structured</h2>
              <p className="iris-subtitle">
                Each hub starts with emergency intent messaging, then moves into practical response education:
                definition, first-response priorities, process steps, local route links, and FAQs. The objective is to
                keep pages useful for users while remaining highly extractable for search and AI systems.
              </p>
            </div>
            <div className="iris-card iris-card-pad">
              <h3 className="text-xl font-bold text-[#0d2d44]">What You Can Expect</h3>
              <ul className="mt-4 space-y-2 text-sm text-[#425264]">
                <li>Hero-led emergency positioning</li>
                <li>Content-rich service explanation</li>
                <li>City-level internal linking structure</li>
                <li>Direct 24/7 call-to-action flow</li>
              </ul>
            </div>
          </div>
        </div>
      </section>
    </main>
  );
}
